function generate(input, lib) {
  const text = (input && input.text != null) ? String(input.text) : String(input || '');
  let out = text;
  out = out.replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[REDACTED:SSN]');
  out = out.replace(/\bMRN[:#\s]?\s*\d{4,10}\b/gi, '[REDACTED:MRN]');
  out = out.replace(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b/g, '[REDACTED:EMAIL]');
  out = out.replace(/\b(?:\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g, '[REDACTED:PHONE]');
  out = out.replace(/\b\d{1,2}\/\d{1,2}\/\d{2,4}\b/g, '[REDACTED:DATE]');
  out = out.replace(/\b\d{4}-\d{2}-\d{2}\b/g, '[REDACTED:DATE]');
  out = out.replace(/\b\d{5}(?:-\d{4})?\b/g, '[REDACTED:ZIP]');
  out = out.replace(/\b(?:Mr\.?|Mrs\.?|Ms\.?|Dr\.?)\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+)?\b/g, '[REDACTED:NAME]');
  out = out.replace(/\bPatient[:\s]+[A-Z][a-z]+(?:\s+[A-Z][a-z]+)?\b/g, 'Patient: [REDACTED:NAME]');
  return { redacted: out };
}
